} from '../../utils'
import type { IComputedPosition } from '../../utils'
import coreStyles from './core-styles.module.css'
import styles from './styles.module.css'
import useTooltipAnchors from './use-tooltip-anchors'
import useTooltipEvents from './use-tooltip-events'
import type { IPosition, ITooltip, TooltipImperativeOpenOptions } from './TooltipTypes'

// Shared across all tooltip instances — the CSS variable is on :root and never changes per-instance
let globalTransitionShowDelay: number | null = null

const Tooltip = ({
  // props
  forwardRef,
  id,
  className,
  classNameArrow,
  variant = 'dark',
  portalRoot,
  anchorSelect,
  place = 'top',
  offset = 10,
  openOnClick = false,
  positionStrategy = 'absolute',
  middlewares,
  wrapper: WrapperElement,
  delayShow = 0,
  delayHide = 0,
  autoClose,
  float = false,
  hidden = false,
  noArrow = false,
  clickable = false,
  openEvents,
  closeEvents,
  globalCloseEvents,
  imperativeModeOnly,
  style: externalStyles,
  position,
  afterShow,
  afterHide,
  disableTooltip,
  // props handled by controller
  content,
  contentWrapperRef,
  isOpen,
  defaultIsOpen = false,
  setIsOpen,
  previousActiveAnchor,
  activeAnchor,
  setActiveAnchor,
  border,
  opacity,
  arrowColor,
  arrowSize = 8,
  role = 'tooltip',
}: ITooltip) => {
  const tooltipRef = useRef<HTMLElement>(null)
  const tooltipArrowRef = useRef<HTMLElement>(null)
  const tooltipShowDelayTimerRef = useRef<NodeJS.Timeout | null>(null)
  const tooltipHideDelayTimerRef = useRef<NodeJS.Timeout | null>(null)
  const tooltipAutoCloseTimerRef = useRef<NodeJS.Timeout | null>(null)
  const missedTransitionTimerRef = useRef<NodeJS.Timeout | null>(null)
  const [computedPosition, setComputedPosition] = useState<IComputedPosition>({
    tooltipStyles: {},
    tooltipArrowStyles: {},
    place,
  })
  const [show, setShow] = useState(false)
  const [rendered, setRendered] = useState(false)
  const [imperativeOptions, setImperativeOptions] = useState<TooltipImperativeOpenOptions | null>(
    null,
  )
  const wasShowing = useRef(false)
  const lastFloatPosition = useRef<IPosition | null>(null)
  const hoveringTooltip = useRef(false)
  const mounted = useRef(false)
  const virtualElementRef = useRef({
    getBoundingClientRect: () => ({
      x: 0,
      y: 0,
      width: 0,
      height: 0,
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
    }),
  })

  /**
   * useLayoutEffect runs before useEffect,
   * but should be used carefully because of caveats
   * https://beta.reactjs.org/reference/react/useLayoutEffect#caveats
   */
  useIsomorphicLayoutEffect(() => {
    mounted.current = true
    return () => {
      mounted.current = false
    }
  }, [])

  const handleShow = useCallback(
    (value: boolean) => {
      if (!mounted.current) {
        return
      }
      if (value) {
        setRendered(true)
      }
      /**
       * wait for the component to render and calculate position
       * before actually showing
       */
      setTimeout(() => {
        if (!mounted.current) {
          return
        }
        setIsOpen?.(value)
        if (isOpen === undefined) {
          setShow(value)
        }
      }, 10)
    },
    [isOpen, setIsOpen],
  )

  /**
   * Add aria-describedby to activeAnchor when tooltip is active
   */
  useEffect(() => {
    if (!id) return

    function getAriaDescribedBy(element: HTMLElement | null) {
      return element?.getAttribute('aria-describedby')?.split(' ') || []
    }

    function removeAriaDescribedBy(element: HTMLElement | null) {
      const newDescribedBy = getAriaDescribedBy(element).filter((s) => s !== id)
      if (newDescribedBy.length) {
        element?.setAttribute('aria-describedby', newDescribedBy.join(' '))
      } else {
        element?.removeAttribute('aria-describedby')
      }
    }

    if (show) {
      removeAriaDescribedBy(previousActiveAnchor)
      const currentDescribedBy = getAriaDescribedBy(activeAnchor)
      const describedBy = [...new Set([...currentDescribedBy, id])].filter(Boolean).join(' ')
      activeAnchor?.setAttribute('aria-describedby', describedBy)
    } else {
      removeAriaDescribedBy(activeAnchor)
    }

    return () => {
      // cleanup aria-describedby when the tooltip is closed
      removeAriaDescribedBy(activeAnchor)
      removeAriaDescribedBy(previousActiveAnchor)
    }
  }, [activeAnchor, show, id, previousActiveAnchor])

  /**
   * this replicates the effect from `handleShow()`
   * when `isOpen` is changed from outside
   */
  useEffect(() => {
    if (isOpen === undefined) {
      return () => null
    }
    if (isOpen) {
      setRendered(true)
    }
    const timeout = setTimeout(() => {
      setShow(isOpen)
    }, 10)
    return () => {
      clearTimeout(timeout)
    }
  }, [isOpen])

  useEffect(() => {
    if (show === wasShowing.current) {
      return
    }
    clearTimeoutRef(missedTransitionTimerRef)
    wasShowing.current = show
    if (show) {
      afterShow?.()
    } else {
      /**
       * see `onTransitionEnd` on tooltip wrapper
       */
      if (globalTransitionShowDelay === null) {
        const style = getComputedStyle(document.body)
        globalTransitionShowDelay = cssTimeToMs(
          style.getPropertyValue('--rt-transition-show-delay'),
        )
      }
      const transitionShowDelay = globalTransitionShowDelay
      missedTransitionTimerRef.current = setTimeout(() => {
        /**
         * if the tooltip switches from `show === true` to `show === false` too fast
         * the transition never runs, so `onTransitionEnd` callback never gets fired
         */
        setRendered(false)
        setImperativeOptions(null)
        afterHide?.()
        // +25ms just to make sure `onTransitionEnd` (if it gets fired) has time to run
      }, transitionShowDelay + 25)
    }
  }, [afterHide, afterShow, show])

  useEffect(() => {
    clearTimeoutRef(tooltipAutoCloseTimerRef)

    if (!show || !autoClose || autoClose <= 0) {
      return () => {
        clearTimeoutRef(tooltipAutoCloseTimerRef)
      }
    }

    tooltipAutoCloseTimerRef.current = setTimeout(() => {
      handleShow(false)
    }, autoClose)

    return () => {
      clearTimeoutRef(tooltipAutoCloseTimerRef)
    }
  }, [activeAnchor, autoClose, handleShow, show])

  const handleComputedPosition = useCallback((newComputedPosition: IComputedPosition) => {
    if (!mounted.current) {
      return
    }
    setComputedPosition((oldComputedPosition) => {
      if (
        oldComputedPosition.place === newComputedPosition.place &&
        oldComputedPosition.tooltipStyles.left === newComputedPosition.tooltipStyles.left &&
        oldComputedPosition.tooltipStyles.top === newComputedPosition.tooltipStyles.top &&
        oldComputedPosition.tooltipStyles.border === newComputedPosition.tooltipStyles.border &&
        oldComputedPosition.tooltipArrowStyles.left ===
          newComputedPosition.tooltipArrowStyles.left &&
        oldComputedPosition.tooltipArrowStyles.top === newComputedPosition.tooltipArrowStyles.top &&
        oldComputedPosition.tooltipArrowStyles.right ===
          newComputedPosition.tooltipArrowStyles.right &&
        oldComputedPosition.tooltipArrowStyles.bottom ===
          newComputedPosition.tooltipArrowStyles.bottom &&
        oldComputedPosition.tooltipArrowStyles.borderBottom ===
          newComputedPosition.tooltipArrowStyles.borderBottom &&
        oldComputedPosition.tooltipArrowStyles.borderRight ===
          newComputedPosition.tooltipArrowStyles.borderRight
      ) {
        return oldComputedPosition
      }
      return newComputedPosition
    })
  }, [])

  const handleShowTooltipDelayed = useCallback(
    (delay = delayShow) => {
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }

